import CartContext from './CartContext'
import React,{useState} from 'react'

function CartState(props) {
    const host = "http://localhost:5000"
    const cartinitial = []
    const [cart, setcart] = useState(cartinitial)


    //add tp cart
    const addtocart = async (id,image,title) => {
        const response = await fetch(`${host}/api/auth/addToCart?productId=${_id}`, {
            method: "POST",
            headers: {
                'Content-Type': 'application/json',
                'auth-token': localStorage.getItem('token')
            },
            body: JSON.stringify({firstname,lastname,address,city,state,pincode,country,phone}),
        });

        const profile = await response.json()
        setProfiles(profiles.concat(profile));
    };
    return (
        <CartContext.Provider value={{cart,setcart,addtocart} }>
            {props.children};
        </CartContext.Provider>
    )
}

export default CartState
